+:root {
+    --bg: #1a1a2e;
+    --bg-secondary: #16213e;
+    --text: #eee;
+    --text-muted: #888;
+    --accent: #4a9eff;
+    --border: #333;
+}
+
+* { box-sizing: border-box; }
+
+body {
+    font-family: system-ui, -apple-system, sans-serif;
+    background: var(--bg);
+    color: var(--text);
+    margin: 0;
+    padding: 0;
+    line-height: 1.6;
+}
+
+nav {
+    background: var(--bg-secondary);
+    padding: 1rem 2rem;
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    border-bottom: 1px solid var(--border);
+}
+
+nav h1, nav a {
+    color: var(--accent);
+    text-decoration: none;
+    margin: 0;
+    font-size: 1.2rem;
+}
+
+nav form {
+    display: flex;
+    gap: 0.5rem;
+}
+
+nav input[type="text"] {
+    padding: 0.5rem;
+    border: 1px solid var(--border);
+    border-radius: 4px;
+    background: var(--bg);
+    color: var(--text);
+    width: 300px;
+}
+
+nav button {
+    padding: 0.5rem 1rem;
+    background: var(--accent);
+    color: white;
+    border: none;
+    border-radius: 4px;
+    cursor: pointer;
+}
+
+main {
+    padding: 2rem;
+    max-width: 1200px;
+    margin: 0 auto;
+}
+
+h2, h3 {
+    color: var(--text);
+    border-bottom: 1px solid var(--border);
+    padding-bottom: 0.5rem;
+}
+
+.session {
+    padding: 0.5rem 0;
+    display: flex;
+    gap: 1rem;
+    align-items: center;
+}
+
+.session a {
+    color: var(--accent);
+    font-family: monospace;
+}
+
+.session .host {
+    color: var(--text-muted);
+    font-size: 0.9rem;
+}
